import React, { useState, useEffect } from 'react';
import './ImportDataSidebar.css';

function ImportDataSidebar({ onSelectUserStory, onClose }) {
  const [jiraData, setJiraData] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  // Function to fetch Jira data
  const fetchJiraData = async () => {
    setLoading(true);
    try {
      const response = await fetch('');
      if (!response.ok) {
        throw new Error('Failed to fetch Jira data');
      }
      const data = await response.json();
      console.log('Jira Data:', data);  // Log the data to verify it
      setJiraData(data);  // Set the data in the state
    } catch (err) {
      console.error('Error fetching Jira data:', err);
      setError('Error fetching Jira data. Please try again later.');
    } finally {
      setLoading(false);
    }
  };

  // Fetch Jira data when the component mounts
  useEffect(() => {
    fetchJiraData();
  }, []);

  return (
    <div className="import-sidebar">
      <button className="close-btn" onClick={onClose}>X</button>
      <div className="sidebar-title">Imported Jira User Stories</div>
      
      {/* Show loading spinner while data is loading */}
      {loading && <div>Loading...</div>}

      {/* Show error message if there's an issue fetching data */}
      {error && <div className="error">{error}</div>}

      <div className="jira-stories">
        {jiraData.length === 0 && !loading ? (
          <div>No Jira stories found.</div>
        ) : (
          jiraData.map((story) => (
            <div
              key={story.Key}  // Using Key as the unique identifier
              className="jira-story-box"
              onClick={() => onSelectUserStory(story.Summary)}  // Pass story summary or any relevant data
            >
              {story.Summary}
            </div>
          ))
        )}
      </div>
    </div>
  );
}

export default ImportDataSidebar;
